const ai = $node["AI_Node"].json;
const webhook = $node["Webhook Inbound"].json;
const rawContent = ai.choices?.[0]?.message?.content || "{}";
let parsed = {};
try {
  parsed = JSON.parse(rawContent.replace(/```json|```/g, '').trim());
} catch (e) {
  parsed = { categoria: "CAT_VARIOS", translations: { es: { titulo: "Error AI", descripcion: "Parse failure" } } };
}

// 1. FILTRO CERO BASURA (ANTI-VARIOS)
const validCats = ["CAT_PLAZAS", "CAT_EVENTOS", "CAT_AGENCY", "CAT_MODELOS", "CAT_VARIOS"];
let finalCat = parsed.categoria;
const rawText = (webhook.body?.text || "").toLowerCase();

if (!validCats.includes(finalCat)) {
    if (rawText.includes("fija") || rawText.includes("staff") || rawText.includes("club")) {
        finalCat = "CAT_PLAZAS";
    } else {
        finalCat = "CAT_VARIOS";
    }
}

// 3. BLINDAJE DE DUPLICADOS (Deduplication)
// Generamos un ID único basado en el message_id de Telegram o un hash simple del texto
const external_id = webhook.body?.message_id || 
                   webhook.body?.update_id || 
                   Math.abs(rawText.split('').reduce((a,b)=>{a=((a<<5)-a)+b.charCodeAt(0);return a&a},0)).toString();

return {
  categoria: finalCat,
  translations: parsed.translations,
  ubicacion: parsed.ubicacion || "Global",
  contacto: parsed.contacto || "Ver en Telegram",
  activa: true,
  timestamp: new Date().toISOString(),
  platform: webhook.body?.platform || "TELEGRAM",
  external_id: external_id.toString()
};
